     1→"use client";
     2→
     3→import useSWR from "swr";
     4→import Link from "next/link";
     5→import { projects as projectsApi, sources as sourcesApi } from "@/lib/api/client";
     6→import { Card, CardContent } from "@/components/ui/card";
     7→import { Badge } from "@/components/ui/badge";
     8→import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
     9→import type { Source } from "@/lib/api/types";
    10→
    11→interface SourceWithProject extends Source {
    12→  projectName?: string;
    13→}
    14→
    15→export default function SourcesPage() {
    16→  const { data: projectsData } = useSWR("projects-for-sources", () => projectsApi.list());
    17→
    18→  const { data: allSources, isLoading } = useSWR(
    19→    projectsData ? "all-sources" : null,
    20→    async () => {
    21→      if (!projectsData?.data?.length) return [];
    22→      const results = await Promise.all(
    23→        projectsData.data.map(async (p) => {
    24→          const res = await sourcesApi.listByProject(p.id).catch(() => null);
    25→          return (res?.data ?? []).map((s) => ({ ...s, projectName: p.name }));
    26→        })
    27→      );
    28→      return results.flat() as SourceWithProject[];
    29→    }
    30→  );
    31→
    32→  return (
    33→    <div className="space-y-4">
    34→      <div>
    35→        <h2 className="text-lg font-semibold">All Sources</h2>
    36→        <p className="text-sm text-muted-foreground">
    37→          Ingestion sources across all projects. Sources are managed within their project.
    38→        </p>
    39→      </div>
    40→      <Card>
    41→        <CardContent className="p-0">
    42→          {isLoading ? (
    43→            <div className="py-12 text-center text-muted-foreground">Loading...</div>
    44→          ) : (
    45→            <Table>
    46→              <TableHeader>
    47→                <TableRow>
    48→                  <TableHead>Repository</TableHead>
    49→                  <TableHead>Provider</TableHead>
    50→                  <TableHead>Project</TableHead>
    51→                  <TableHead>Poll Interval</TableHead>
    52→                  <TableHead>Last Polled</TableHead>
    53→                  <TableHead>Status</TableHead>
    54→                </TableRow>
    55→              </TableHeader>
    56→              <TableBody>
    57→                {(allSources ?? []).map((source) => (
    58→                  <TableRow key={source.id}>
    59→                    <TableCell>
    60→                      <Link href={`/sources/${source.id}/edit`} className="font-mono text-sm text-primary hover:underline">{source.repository}</Link>
    61→                    </TableCell>
    62→                    <TableCell><Badge variant="outline">{source.provider}</Badge></TableCell>
    63→                    <TableCell>
    64→                      <Link href={`/projects/${source.project_id}`} className="text-primary hover:underline">
    65→                        {source.projectName ?? source.project_id}
    66→                      </Link>
    67→                    </TableCell>
    68→                    <TableCell className="text-sm">{source.poll_interval_seconds}s</TableCell>
    69→                    <TableCell className="text-sm text-muted-foreground">{source.last_polled_at ? new Date(source.last_polled_at).toLocaleString() : "Never"}</TableCell>
    70→                    <TableCell>
    71→                      {source.last_error ? (
    72→                        <Badge variant="destructive" className="text-xs">{source.last_error}</Badge>
    73→                      ) : (
    74→                        <Badge variant={source.enabled ? "default" : "secondary"}>{source.enabled ? "active" : "disabled"}</Badge>
    75→                      )}
    76→                    </TableCell>
    77→                  </TableRow>
    78→                ))}
    79→              </TableBody>
    80→            </Table>
    81→          )}
    82→        </CardContent>
    83→      </Card>
    84→    </div>
    85→  );
    86→}
