     1→"use client";
     2→
     3→import useSWR from "swr";
     4→import Link from "next/link";
     5→import { useState } from "react";
     6→import { useRouter } from "next/navigation";
     7→import {
     8→  projects as projectsApi,
     9→  sources as sourcesApi,
    10→  contextSources as ctxApi,
    11→  semanticReleases as srApi,
    12→  agent as agentApi,
    13→} from "@/lib/api/client";
    14→import type { AgentRules } from "@/lib/api/types";
    15→import { ProviderBadge } from "@/components/ui/provider-badge";
    16→import { StatusDot } from "@/components/ui/status-dot";
    17→import { VersionChip } from "@/components/ui/version-chip";
    18→import { SectionLabel } from "@/components/ui/section-label";
    19→import { Pencil, Trash2, Play, Plus } from "lucide-react";
    20→
    21→/* ---------- Tabs ---------- */
    22→
    23→const tabs = [
    24→  { key: "sources", label: "Sources" },
    25→  { key: "context", label: "Context Sources" },
    26→  { key: "semantic", label: "Semantic Releases" },
    27→  { key: "agent", label: "Agent" },
    28→] as const;
    29→
    30→type TabKey = (typeof tabs)[number]["key"];
    31→
    32→/* ---------- Helpers ---------- */
    33→
    34→function formatDuration(startedAt?: string, completedAt?: string): string {
    35→  if (!startedAt) return "--";
    36→  const start = new Date(startedAt).getTime();
    37→  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
    38→  const secs = Math.round((end - start) / 1000);
    39→  if (secs < 60) return `${secs}s`;
    40→  const mins = Math.floor(secs / 60);
    41→  const rem = secs % 60;
    42→  return `${mins}m ${rem}s`;
    43→}
    44→
    45→function truncate(str: string, max: number): string {
    46→  return str.length > max ? str.slice(0, max) + "\u2026" : str;
    47→}
    48→
    49→function formatInterval(seconds: number): string {
    50→  if (seconds < 60) return `${seconds}s`;
    51→  if (seconds < 3600) return `${Math.round(seconds / 60)}m`;
    52→  return `${(seconds / 3600).toFixed(1)}h`;
    53→}
    54→
    55→/* ---------- Urgency chip ---------- */
    56→
    57→const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
    58→  critical: { bg: "#dc2626", text: "#ffffff" },
    59→  high: { bg: "#f97316", text: "#ffffff" },
    60→};
    61→
    62→function UrgencyChip({ urgency }: { urgency: string }) {
    63→  const u = urgency.toLowerCase();
    64→  const style = URGENCY_COLORS[u];
    65→  if (!style) return null;
    66→  return (
    67→    <span
    68→      className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium leading-none"
    69→      style={{ backgroundColor: style.bg, color: style.text }}
    70→    >
    71→      {urgency}
    72→    </span>
    73→  );
    74→}
    75→
    76→/* ---------- Main component ---------- */
    77→
    78→export function ProjectDetail({ id }: { id: string }) {
    79→  const router = useRouter();
    80→  const [activeTab, setActiveTab] = useState<TabKey>("sources");
    81→  const [triggering, setTriggering] = useState(false);
    82→
    83→  /* Agent config local state */
    84→  const [promptDraft, setPromptDraft] = useState<string | null>(null);
    85→  const [rulesDraft, setRulesDraft] = useState<AgentRules | null>(null);
    86→  const [saving, setSaving] = useState(false);
    87→
    88→  /* Data fetching */
    89→  const { data, isLoading, mutate: mutateProject } = useSWR(`project-${id}`, () => projectsApi.get(id));
    90→  const { data: sourcesData, mutate: mutateSources } = useSWR(
    91→    activeTab === "sources" ? `project-${id}-sources` : null,
    92→    () => sourcesApi.listByProject(id),
    93→  );
    94→  const { data: ctxData, mutate: mutateCtx } = useSWR(
    95→    activeTab === "context" ? `project-${id}-ctx` : null,
    96→    () => ctxApi.list(id),
    97→  );
    98→  const { data: srData } = useSWR(
    99→    activeTab === "semantic" ? `project-${id}-sr` : null,
   100→    () => srApi.list(id),
   101→  );
   102→  const { data: runsData, mutate: mutateRuns } = useSWR(
   103→    activeTab === "agent" ? `project-${id}-runs` : null,
   104→    () => agentApi.listRuns(id),
   105→  );
   106→
   107→  /* Handlers */
   108→  const handleDelete = async () => {
   109→    if (!confirm("Delete this project? This will cascade to sources and subscriptions.")) return;
   110→    await projectsApi.delete(id);
   111→    router.push("/projects");
   112→  };
   113→
   114→  const handleTriggerRun = async () => {
   115→    setTriggering(true);
   116→    try {
   117→      await agentApi.triggerRun(id);
   118→      mutateRuns();
   119→    } finally {
   120→      setTriggering(false);
   121→    }
   122→  };
   123→
   124→  const handleDeleteSource = async (sourceId: string) => {
   125→    if (!confirm("Delete this source?")) return;
   126→    await sourcesApi.delete(sourceId);
   127→    mutateSources();
   128→  };
   129→
   130→  const handleDeleteCtx = async (ctxId: string) => {
   131→    if (!confirm("Delete this context source?")) return;
   132→    await ctxApi.delete(ctxId);
   133→    mutateCtx();
   134→  };
   135→
   136→  const handleSaveAgentConfig = async () => {
   137→    if (!project) return;
   138→    setSaving(true);
   139→    try {
   140→      const input = {
   141→        name: project.name,
   142→        description: project.description,
   143→        agent_prompt: promptDraft ?? project.agent_prompt,
   144→        agent_rules: rulesDraft ?? project.agent_rules,
   145→      };
   146→      await projectsApi.update(id, input);
   147→      mutateProject();
   148→      setPromptDraft(null);
   149→      setRulesDraft(null);
   150→    } finally {
   151→      setSaving(false);
   152→    }
   153→  };
   154→
   155→  /* Loading / not found states */
   156→  if (isLoading) {
   157→    return (
   158→      <div className="flex h-48 items-center justify-center" style={{ color: "#9ca3af" }}>
   159→        Loading...
   160→      </div>
   161→    );
   162→  }
   163→
   164→  const project = data?.data;
   165→  if (!project) {
   166→    return (
   167→      <div className="flex h-48 items-center justify-center" style={{ color: "#6b7280" }}>
   168→        Project not found
   169→      </div>
   170→    );
   171→  }
   172→
   173→  /* Derived counts */
   174→  const sourceCount = sourcesData?.data?.length;
   175→  const ctxCount = ctxData?.data?.length;
   176→
   177→  /* Current effective values */
   178→  const currentPrompt = promptDraft ?? project.agent_prompt ?? "";
   179→  const currentRules: AgentRules = rulesDraft ?? project.agent_rules ?? {};
   180→
   181→  return (
   182→    <div className="space-y-0">
   183→      {/* ===== Header zone ===== */}
   184→      <div
   185→        className="-m-6 mb-0 border-b px-6 py-5"
   186→        style={{ backgroundColor: "#ffffff", borderColor: "#e8e8e5" }}
   187→      >
   188→        <div className="flex items-start justify-between">
   189→          {/* Left: project info */}
   190→          <div className="min-w-0 flex-1">
   191→            <h1
   192→              className="text-[28px] font-bold leading-tight"
   193→              style={{ fontFamily: "var(--font-fraunces), serif" }}
   194→            >
   195→              {project.name}
   196→            </h1>
   197→            {project.description && (
   198→              <p
   199→                className="mt-1 text-[14px]"
   200→                style={{ fontFamily: "var(--font-dm-sans), sans-serif", color: "#6b7280" }}
   201→              >
   202→                {project.description}
   203→              </p>
   204→            )}
   205→            <p
   206→              className="mt-2 text-[12px]"
   207→              style={{ fontFamily: "var(--font-dm-sans), sans-serif", color: "#9ca3af" }}
   208→            >
   209→              {sourceCount !== undefined ? `${sourceCount} sources` : "-- sources"}
   210→              {" \u00B7 "}
   211→              {ctxCount !== undefined ? `${ctxCount} context sources` : "-- context sources"}
   212→            </p>
   213→          </div>
   214→
   215→          {/* Right: actions */}
   216→          <div className="flex shrink-0 items-center gap-2 ml-4">
   217→            <Link href={`/projects/${id}/edit`}>
   218→              <button
   219→                className="inline-flex items-center gap-1.5 rounded-md border px-3 py-1.5 text-[13px] font-medium transition-colors hover:bg-[#f3f3f1]"
   220→                style={{
   221→                  fontFamily: "var(--font-dm-sans), sans-serif",
   222→                  borderColor: "#e8e8e5",
   223→                  color: "#374151",
   224→                }}
   225→              >
   226→                <Pencil className="h-3.5 w-3.5" />
   227→                Edit
   228→              </button>
   229→            </Link>
   230→            <button
   231→              onClick={handleDelete}
   232→              className="inline-flex items-center gap-1.5 rounded-md border px-3 py-1.5 text-[13px] font-medium transition-colors hover:bg-red-50"
   233→              style={{
   234→                fontFamily: "var(--font-dm-sans), sans-serif",
   235→                borderColor: "#dc2626",
   236→                color: "#dc2626",
   237→              }}
   238→            >
   239→              <Trash2 className="h-3.5 w-3.5" />
   240→              Delete
   241→            </button>
   242→            <button
   243→              onClick={handleTriggerRun}
   244→              disabled={triggering}
   245→              className="inline-flex items-center gap-1.5 rounded-md px-3 py-1.5 text-[13px] font-medium text-white transition-colors disabled:opacity-60"
   246→              style={{
   247→                fontFamily: "var(--font-dm-sans), sans-serif",
   248→                backgroundColor: "#e8601a",
   249→              }}
   250→            >
   251→              <Play className="h-3.5 w-3.5" />
   252→              {triggering ? "Running..." : "Run Agent"}
   253→            </button>
   254→          </div>
   255→        </div>
   256→      </div>
   257→
   258→      {/* ===== Tab bar ===== */}
   259→      <div
   260→        className="-mx-6 border-b px-6"
   261→        style={{ borderColor: "#e8e8e5", backgroundColor: "#ffffff" }}
   262→      >
   263→        <div className="flex gap-0">
   264→          {tabs.map((tab) => {
   265→            const isActive = activeTab === tab.key;
   266→            return (
   267→              <button
   268→                key={tab.key}
   269→                onClick={() => setActiveTab(tab.key)}
   270→                className="relative px-4 py-2.5 text-[13px] font-medium transition-colors"
   271→                style={{
   272→                  fontFamily: "var(--font-dm-sans), sans-serif",
   273→                  color: isActive ? "#111113" : "#9ca3af",
   274→                }}
   275→              >
   276→                {tab.label}
   277→                {isActive && (
   278→                  <span
   279→                    className="absolute bottom-0 left-4 right-4 h-[2px]"
   280→                    style={{ backgroundColor: "#e8601a" }}
   281→                  />
   282→                )}
   283→              </button>
   284→            );
   285→          })}
   286→        </div>
   287→      </div>
   288→
   289→      {/* ===== Tab content ===== */}
   290→      <div className="pt-6">
   291→        {/* --- Sources tab --- */}
   292→        {activeTab === "sources" && (
   293→          <div>
   294→            <div className="mb-4 flex items-center justify-between">
   295→              <SectionLabel>Sources</SectionLabel>
   296→              <Link href={`/projects/${id}/sources/new`}>
   297→                <button
   298→                  className="inline-flex items-center gap-1.5 rounded-md border px-3 py-1.5 text-[13px] font-medium transition-colors hover:bg-[#f3f3f1]"
   299→                  style={{
   300→                    fontFamily: "var(--font-dm-sans), sans-serif",
