// --- Response Envelope ---

export interface ApiResponse<T> {
  data: T;
  meta?: ApiMeta;
  error?: ApiError;
}

export interface ApiMeta {
  page: number;
  per_page: number;
  total: number;
}

export interface ApiError {
  code: string;
  message: string;
}

// --- Domain Models (all IDs are UUID strings) ---

export interface Project {
  id: string;
  name: string;
  description?: string;
  agent_prompt?: string;
  agent_rules?: AgentRules;
  created_at: string;
  updated_at: string;
}

export interface AgentRules {
  on_major_release?: boolean;
  on_minor_release?: boolean;
  on_security_patch?: boolean;
  version_pattern?: string;
}

export interface ProjectInput {
  name: string;
  description?: string;
  agent_prompt?: string;
  agent_rules?: AgentRules;
}

export interface Source {
  id: string;
  project_id: string;
  provider: string;
  repository: string;
  poll_interval_seconds: number;
  enabled: boolean;
  config?: Record<string, unknown>;
  last_polled_at?: string;
  last_error?: string;
  created_at: string;
  updated_at: string;
}

export interface SourceInput {
  provider: string;
  repository: string;
  poll_interval_seconds: number;
  enabled: boolean;
  config?: Record<string, unknown>;
}

export interface Release {
  id: string;
  source_id: string;
  version: string;
  raw_data?: Record<string, unknown>;
  released_at?: string;
  created_at: string;
}

export interface ContextSource {
  id: string;
  project_id: string;
  type: string;
  name: string;
  config: Record<string, unknown>;
  created_at: string;
  updated_at: string;
}

export interface ContextSourceInput {
  type: string;
  name: string;
  config: Record<string, unknown>;
}

export interface SemanticRelease {
  id: string;
  project_id: string;
  version: string;
  report?: SemanticReport;
  status: string;
  error?: string;
  created_at: string;
  completed_at?: string;
}

export interface SemanticReport {
  summary: string;
  availability: string;
  adoption: string;
  urgency: string;
  recommendation: string;
}

export interface AgentRun {
  id: string;
  project_id: string;
  semantic_release_id?: string;
  trigger: string;
  status: string;
  prompt_used?: string;
  error?: string;
  started_at?: string;
  completed_at?: string;
  created_at: string;
}

export interface NotificationChannel {
  id: string;
  name: string;
  type: string;
  config: Record<string, unknown>;
  created_at: string;
  updated_at: string;
}

export interface ChannelInput {
  type: string;
  name: string;
  config: Record<string, unknown>;
}

export interface Subscription {
  id: string;
  channel_id: string;
  type: "source" | "project";
  source_id?: string;
  project_id?: string;
  version_filter?: string;
  created_at: string;
}

export interface SubscriptionInput {
  channel_id: string;
  type: "source" | "project";
  source_id?: string;
  project_id?: string;
  version_filter?: string;
}

// --- System Types ---

export interface HealthStatus {
  status: string;
  database: string;
}

export interface Stats {
  total_projects: number;
  total_sources: number;
  total_releases: number;
  pending_agent_runs: number;
}

// --- SSE Event Types ---

export type SSEEventType = "release" | "semantic_release";

interface SSEBase {
  id: string;
  timestamp: string;
}

export type SSEEvent =
  | (SSEBase & {
      type: "release";
      data: { id: string; source_id: string; version: string; created_at: string };
    })
  | (SSEBase & {
      type: "semantic_release";
      data: { id: string; project_id: string; version: string; status: string };
    });

