     1→"use client";
     2→
     3→import { useState } from "react";
     4→import useSWR from "swr";
     5→import Link from "next/link";
     6→import {
     7→  releases as releasesApi,
     8→  projects as projectsApi,
     9→  sources as sourcesApi,
    10→} from "@/lib/api/client";
    11→import { ProviderBadge } from "@/components/ui/provider-badge";
    12→import { VersionChip } from "@/components/ui/version-chip";
    13→import type { Release, Source, Project } from "@/lib/api/types";
    14→import { ExternalLink } from "lucide-react";
    15→
    16→import { timeAgo } from "@/lib/format";
    17→
    18→interface ReleaseRow extends Release {
    19→  _projectName?: string;
    20→  _projectId?: string;
    21→  _provider?: string;
    22→  _repository?: string;
    23→}
    24→
    25→const PER_PAGE = 15;
    26→
    27→function getProviderUrl(
    28→  provider: string,
    29→  repository: string,
    30→  version: string
    31→): string | null {
    32→  switch (provider) {
    33→    case "github":
    34→      return `https://github.com/${repository}/releases/tag/${version}`;
    35→    case "dockerhub":
    36→      return `https://hub.docker.com/r/${repository}/tags?name=${encodeURIComponent(version)}`;
    37→    default:
    38→      return null;
    39→  }
    40→}
    41→
    42→/* ------------------------------------------------------------------ */
    43→/*  Page                                                               */
    44→/* ------------------------------------------------------------------ */
    45→
    46→export default function ReleasesPage() {
    47→  const [page, setPage] = useState(1);
    48→  const [projectFilter, setProjectFilter] = useState<string>("all");
    49→
    50→  /* Fetch projects for the filter dropdown + source enrichment */
    51→  const { data: projectsData } = useSWR("projects-for-filter", () =>
    52→    projectsApi.list()
    53→  );
    54→
    55→  /* Build a map: sourceId -> { provider, repository, projectName, projectId } */
    56→  const { data: sourceMap } = useSWR(
    57→    projectsData ? "source-map-for-releases" : null,
    58→    async () => {
    59→      if (!projectsData?.data?.length) return new Map<string, { provider: string; repository: string; projectName: string; projectId: string }>();
    60→      const map = new Map<string, { provider: string; repository: string; projectName: string; projectId: string }>();
    61→      await Promise.all(
    62→        projectsData.data.map(async (p: Project) => {
    63→          const res = await sourcesApi.listByProject(p.id).catch(() => null);
    64→          if (res?.data) {
    65→            for (const s of res.data) {
    66→              map.set(s.id, {
    67→                provider: s.provider,
    68→                repository: s.repository,
    69→                projectName: p.name,
    70→                projectId: p.id,
    71→              });
    72→            }
    73→          }
    74→        })
    75→      );
    76→      return map;
    77→    }
    78→  );
    79→
    80→  /* Fetch releases — scoped by project or aggregated across all */
    81→  const { data: scopedData, isLoading: scopedLoading } = useSWR(
    82→    projectFilter !== "all" ? ["releases", page, projectFilter] : null,
    83→    () => releasesApi.listByProject(projectFilter, page)
    84→  );
    85→
    86→  const { data: allReleasesData, isLoading: allLoading } = useSWR(
    87→    projectFilter === "all" && projectsData
    88→      ? ["all-releases", page]
    89→      : null,
    90→    async () => {
    91→      if (!projectsData?.data?.length) return [];
    92→      const results = await Promise.all(
    93→        projectsData.data.map((p: Project) =>
    94→          releasesApi.listByProject(p.id, page).catch(() => null)
    95→        )
    96→      );
    97→      return results
    98→        .filter((r): r is NonNullable<typeof r> => r !== null)
    99→        .flatMap((r) => r.data)
   100→        .sort(
   101→          (a, b) =>
   102→            new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
   103→        );
   104→    }
   105→  );
   106→
   107→  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;
   108→
   109→  /* Enrich releases with source metadata */
   110→  const rawReleases: Release[] =
   111→    projectFilter !== "all"
   112→      ? scopedData?.data ?? []
   113→      : allReleasesData ?? [];
   114→
   115→  const releases: ReleaseRow[] = rawReleases.map((r) => {
   116→    const info = sourceMap?.get(r.source_id);
   117→    return {
   118→      ...r,
   119→      _projectName: info?.projectName,
   120→      _projectId: info?.projectId,
   121→      _provider: info?.provider,
   122→      _repository: info?.repository,
   123→    };
   124→  });
   125→
   126→  /* Pagination math */
   127→  const total = projectFilter !== "all" ? (scopedData?.meta?.total ?? 0) : releases.length;
   128→  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
   129→  const startRow = (page - 1) * PER_PAGE + 1;
   130→  const endRow = Math.min(page * PER_PAGE, total);
   131→
   132→  return (
   133→    <div className="space-y-6">
   134→      {/* Page title */}
   135→      <h1
   136→        style={{
   137→          fontFamily: "var(--font-fraunces)",
   138→          fontSize: "24px",
   139→          fontWeight: 700,
   140→          color: "#111113",
   141→        }}
   142→      >
   143→        Releases
   144→      </h1>
   145→
   146→      {/* Project filter */}
   147→      <div>
   148→        <select
   149→          value={projectFilter}
   150→          onChange={(e) => {
   151→            setProjectFilter(e.target.value);
   152→            setPage(1);
   153→          }}
   154→          className="appearance-none rounded-md bg-white px-3 py-2 pr-8 outline-none transition-shadow"
   155→          style={{
   156→            fontFamily: "var(--font-dm-sans)",
   157→            fontSize: "13px",
   158→            color: "#111113",
   159→            border: "1px solid #e8e8e5",
   160→          }}
   161→          onFocus={(e) =>
   162→            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
   163→          }
   164→          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
   165→        >
   166→          <option value="all">All Projects</option>
   167→          {projectsData?.data.map((p: Project) => (
   168→            <option key={p.id} value={p.id}>
   169→              {p.name}
   170→            </option>
   171→          ))}
   172→        </select>
   173→      </div>
   174→
   175→      {/* Table card */}
   176→      <div
   177→        className="overflow-hidden rounded-lg bg-white"
   178→        style={{ border: "1px solid #e8e8e5" }}
   179→      >
   180→        {isLoading ? (
   181→          <div
   182→            className="py-16 text-center"
   183→            style={{
   184→              fontFamily: "var(--font-dm-sans)",
   185→              fontSize: "13px",
   186→              color: "#6b7280",
   187→            }}
   188→          >
   189→            Loading...
   190→          </div>
   191→        ) : releases.length === 0 ? (
   192→          <div className="py-16 text-center">
   193→            <p
   194→              style={{
   195→                fontFamily: "var(--font-fraunces)",
   196→                fontStyle: "italic",
   197→                fontSize: "15px",
   198→                color: "#9ca3af",
   199→              }}
   200→            >
   201→              No releases ingested yet
   202→            </p>
   203→          </div>
   204→        ) : (
   205→          <table className="w-full">
   206→            <thead>
   207→              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
   208→                {["Project", "Provider", "Repository", "Version", "Released", "Age", ""].map(
   209→                  (col) => (
   210→                    <th
   211→                      key={col}
   212→                      className="px-4 py-3 text-left"
   213→                      style={{
   214→                        fontFamily: "var(--font-dm-sans)",
   215→                        fontSize: "11px",
   216→                        fontWeight: 600,
   217→                        textTransform: "uppercase" as const,
   218→                        letterSpacing: "0.08em",
   219→                        color: "#9ca3af",
   220→                      }}
   221→                    >
   222→                      {col}
   223→                    </th>
   224→                  )
   225→                )}
   226→              </tr>
   227→            </thead>
   228→            <tbody>
   229→              {releases.map((release) => (
   230→                <tr
   231→                  key={release.id}
   232→                  className="transition-colors hover:bg-[#fafaf9]"
   233→                  style={{ borderBottom: "1px solid #e8e8e5" }}
   234→                >
   235→                  {/* Project */}
   236→                  <td className="px-4 py-3">
   237→                    {release._projectId ? (
   238→                      <Link
   239→                        href={`/projects/${release._projectId}`}
   240→                        className="hover:underline"
   241→                        style={{
   242→                          fontFamily: "var(--font-dm-sans)",
   243→                          fontSize: "13px",
   244→                          color: "#111113",
   245→                          fontWeight: 500,
   246→                        }}
   247→                      >
   248→                        {release._projectName ?? "\u2014"}
   249→                      </Link>
   250→                    ) : (
   251→                      <span
   252→                        style={{
   253→                          fontFamily: "var(--font-dm-sans)",
   254→                          fontSize: "13px",
   255→                          color: "#9ca3af",
   256→                        }}
   257→                      >
   258→                        {"\u2014"}
   259→                      </span>
   260→                    )}
   261→                  </td>
   262→
   263→                  {/* Provider */}
   264→                  <td className="px-4 py-3">
   265→                    {release._provider ? (
   266→                      <ProviderBadge provider={release._provider} />
   267→                    ) : (
   268→                      <span
   269→                        style={{
   270→                          fontFamily: "var(--font-dm-sans)",
   271→                          fontSize: "13px",
   272→                          color: "#9ca3af",
   273→                        }}
   274→                      >
   275→                        {"\u2014"}
   276→                      </span>
   277→                    )}
   278→                  </td>
   279→
   280→                  {/* Repository */}
   281→                  <td className="px-4 py-3">
   282→                    <span
   283→                      style={{
   284→                        fontFamily: "'JetBrains Mono', monospace",
   285→                        fontSize: "12px",
   286→                        color: "#374151",
   287→                      }}
   288→                    >
   289→                      {release._repository ?? release.source_id}
   290→                    </span>
   291→                  </td>
   292→
   293→                  {/* Version */}
   294→                  <td className="px-4 py-3">
   295→                    <Link href={`/releases/${release.id}`}>
   296→                      <VersionChip version={release.version} />
   297→                    </Link>
   298→                  </td>
   299→
   300→                  {/* Released date */}
   301→                  <td className="px-4 py-3">
   302→                    <span
   303→                      style={{
   304→                        fontFamily: "var(--font-dm-sans)",
   305→                        fontSize: "13px",
   306→                        color: "#6b7280",
   307→                      }}
   308→                    >
   309→                      {release.released_at
   310→                        ? new Date(release.released_at).toLocaleDateString()
   311→                        : "\u2014"}
   312→                    </span>
   313→                  </td>
   314→
   315→                  {/* Age */}
   316→                  <td className="px-4 py-3">
   317→                    <span
   318→                      style={{
   319→                        fontFamily: "var(--font-dm-sans)",
   320→                        fontSize: "13px",
   321→                        color: "#9ca3af",
   322→                      }}
   323→                    >
   324→                      {timeAgo(release.released_at ?? release.created_at)}
   325→                    </span>
   326→                  </td>
   327→
   328→                  {/* Provider link */}
   329→                  <td className="px-4 py-3">
   330→                    {release._provider && release._repository && (() => {
   331→                      const url = getProviderUrl(release._provider, release._repository, release.version);
   332→                      return url ? (
   333→                        <a
   334→                          href={url}
   335→                          target="_blank"
   336→                          rel="noopener noreferrer"
   337→                          className="inline-flex items-center transition-colors hover:opacity-70"
   338→                          style={{ color: "#9ca3af" }}
   339→                          title="View on provider"
   340→                        >
   341→                          <ExternalLink size={14} />
   342→                        </a>
   343→                      ) : null;
   344→                    })()}
   345→                  </td>
   346→                </tr>
   347→              ))}
   348→            </tbody>
   349→          </table>
   350→        )}
   351→      </div>
   352→
   353→      {/* Pagination */}
   354→      {total > 0 && (
   355→        <div className="flex items-center justify-between">
   356→          <span
   357→            style={{
   358→              fontFamily: "var(--font-dm-sans)",
   359→              fontSize: "13px",
   360→              color: "#9ca3af",
   361→            }}
   362→          >
   363→            {startRow}&ndash;{endRow} of {total}
   364→          </span>
   365→          <div className="flex items-center gap-2">
   366→            <button
   367→              disabled={page <= 1}
   368→              onClick={() => setPage(page - 1)}
   369→              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
   370→              style={{
   371→                fontFamily: "var(--font-dm-sans)",
   372→                fontSize: "13px",
   373→                color: "#374151",
   374→                border: "1px solid #e8e8e5",
   375→              }}
   376→            >
   377→              Previous
   378→            </button>
   379→            <button
   380→              disabled={page >= totalPages}
   381→              onClick={() => setPage(page + 1)}
   382→              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
   383→              style={{
   384→                fontFamily: "var(--font-dm-sans)",
   385→                fontSize: "13px",
   386→                color: "#374151",
   387→                border: "1px solid #e8e8e5",
   388→              }}
   389→            >
   390→              Next
   391→            </button>
   392→          </div>
   393→        </div>
   394→      )}
   395→    </div>
   396→  );
   397→}
