    32→    default:
    33→      return null;
    34→  }
    35→}
    36→
    37→function getProviderLabel(provider: string): string {
    38→  switch (provider) {
    39→    case "github":
    40→      return "GitHub";
    41→    case "dockerhub":
    42→      return "Docker Hub";
    43→    default:
    44→      return provider;
    45→  }
    46→}
    47→
    48→/* ------------------------------------------------------------------ */
    49→/*  Component                                                          */
    50→/* ------------------------------------------------------------------ */
    51→
    52→export function ReleaseDetail({ id }: { id: string }) {
