    55→    releasesApi.get(id)
    56→  );
    57→
    58→  const release = releaseData?.data;
    59→
    60→  /* Fetch source info once we have the release */
    61→  const { data: sourceData } = useSWR(
    62→    release ? `source-${release.source_id}` : null,
    63→    () => (release ? sourcesApi.get(release.source_id) : null)
    64→  );
    65→  const source: Source | undefined = sourceData?.data;
    66→
    67→  /* Fetch project info once we have the source */
