   126→        className="inline-flex items-center gap-1.5 transition-colors hover:opacity-70"
   127→        style={{
   128→          fontFamily: "var(--font-dm-sans)",
   129→          fontSize: "13px",
   130→          color: "#6b7280",
   131→        }}
   132→      >
   133→        <ArrowLeft size={14} />
   134→        Back to Releases
   135→      </Link>
   136→
   137→      {/* Header */}
   138→      <div>
   139→        <h1
   140→          style={{
   141→            fontFamily: "var(--font-fraunces)",
   142→            fontSize: "24px",
   143→            fontWeight: 700,
   144→            color: "#111113",
   145→          }}
   146→        >
   147→          Release {release.version}
   148→        </h1>
   149→        <div className="mt-2 flex items-center gap-3">
   150→          {source && <ProviderBadge provider={source.provider} />}
   151→          {source && (
   152→            <span
