   671→// --- OrchestratorStore (agent layer) ---
   672→
   673→// UpdateAgentRunStatus sets the status of an agent run and updates the
   674→// started_at timestamp when transitioning to "running".
   675→func (s *PgStore) UpdateAgentRunStatus(ctx context.Context, id, status string) error {
   676→	var query string
   677→	switch status {
   678→	case "running":
   679→		query = `UPDATE agent_runs SET status = $1, started_at = NOW() WHERE id = $2`
   680→	case "completed":
   681→		query = `UPDATE agent_runs SET status = $1, completed_at = NOW() WHERE id = $2`
   682→	default:
   683→		query = `UPDATE agent_runs SET status = $1 WHERE id = $2`
   684→	}
   685→	tag, err := s.pool.Exec(ctx, query, status, id)
   686→	if err != nil {
   687→		return fmt.Errorf("update agent run status: %w", err)
   688→	}
   689→	if tag.RowsAffected() == 0 {
   690→		return fmt.Errorf("agent run not found: %s", id)
   691→	}
   692→	return nil
   693→}
