   695→// CreateSemanticRelease inserts a semantic release and its source release links
   696→// in a single transaction. The sr.ID field is populated on success.
   697→func (s *PgStore) CreateSemanticRelease(ctx context.Context, sr *models.SemanticRelease, releaseIDs []string) error {
   698→	tx, err := s.pool.Begin(ctx)
   699→	if err != nil {
   700→		return fmt.Errorf("begin tx: %w", err)
   701→	}
   702→	defer tx.Rollback(ctx)
   703→
   704→	err = tx.QueryRow(ctx,
   705→		`INSERT INTO semantic_releases (project_id, version, report, status, completed_at)
   706→		 VALUES ($1, $2, $3, $4, $5)
   707→		 RETURNING id, created_at`,
   708→		sr.ProjectID, sr.Version, sr.Report, sr.Status, sr.CompletedAt,
   709→	).Scan(&sr.ID, &sr.CreatedAt)
   710→	if err != nil {
   711→		return fmt.Errorf("insert semantic release: %w", err)
   712→	}
   713→
   714→	for _, relID := range releaseIDs {
   715→		_, err = tx.Exec(ctx,
   716→			`INSERT INTO semantic_release_sources (semantic_release_id, release_id)
   717→			 VALUES ($1, $2) ON CONFLICT DO NOTHING`,
   718→			sr.ID, relID,
   719→		)
   720→		if err != nil {
   721→			return fmt.Errorf("insert semantic release source: %w", err)
   722→		}
   723→	}
   724→
   725→	return tx.Commit(ctx)
   726→}
